
.modal-mask {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: grid;
  place-items: center;
  padding: 12px;
  background: rgba(0, 0, 0, 0.54);
  backdrop-filter: blur(4px);
}

.vehicle-modal {
  width: min(420px, 92vw);
  max-height: 80vh;
  overflow-y: auto;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 12px;
  background:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(139, 119, 90, 0.04) 2px,
      rgba(139, 119, 90, 0.04) 4px
    ),
    var(--qyc-paper-light);
  color: var(--qyc-ink);
  box-shadow: 0 18px 55px rgba(44, 24, 16, 0.45);
}

.modal-header {
  position: sticky;
  top: 0;
  z-index: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 14px 10px;
  border-bottom: 1px solid var(--qyc-vermilion-faded);
  background: var(--qyc-paper-light);
}

.modal-title {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 17px;
  font-weight: 800;
  letter-spacing: 0.04em;
}

.header-actions {
  display: flex;
  gap: 6px;
  align-items: center;
}

.edit-btn {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 700;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.edit-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.edit-btn.active {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.close-btn {
  width: 28px;
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 14px;
  font-weight: 800;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.close-btn:hover {
  border-color: var(--qyc-danger);
  color: var(--qyc-danger);
}

.detail-section {
  padding: 11px 14px;
  border-bottom: 1px dashed var(--qyc-line);

  &:last-child {
    border-bottom: 0;
  }

  h3 {
    margin: 0 0 9px;
    color: var(--qyc-vermilion);
    font-family: var(--qyc-font-title);
    font-size: 14px;
    letter-spacing: 0.06em;
  }
}

.info-row {
  display: grid;
  grid-template-columns: 96px minmax(0, 1fr);
  gap: 8px;
  align-items: baseline;
  padding: 3px 0;
  font-size: 13px;
}

.info-label {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.info-value {
  color: var(--qyc-ink);
  font-weight: 600;
  word-break: break-word;
}

.list-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 6px 8px;
  align-items: center;
  padding: 5px 0;
  border-top: 1px dotted var(--qyc-line);
  font-size: 13px;

  &:first-of-type {
    border-top: 0;
  }
}

.list-name {
  color: var(--qyc-ink);
  font-weight: 600;
}

.list-badge {
  justify-self: end;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  padding: 2px 8px;
  font-family: var(--qyc-font-mono);
  font-size: 12px;
}

.list-note {
  grid-column: 1 / -1;
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.empty-hint {
  color: var(--qyc-ink-faint);
  font-size: 13px;
  padding: 4px 0;
}

/* ── 编辑模式 ── */
.edit-field {
  display: flex;
  flex-direction: column;
  gap: 3px;
  padding: 4px 0;
  font-size: 13px;
}

.edit-label {
  color: var(--qyc-ink-faint);
  font-size: 11px;
  letter-spacing: 0.06em;
}

.edit-combo {
  display: flex;
  gap: 4px;
}

.edit-record-actions {
  padding: 4px 0 8px;
}

.add-row-btn {
  height: 28px;
  border: 1px dashed var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 600;
  padding: 0 12px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.add-row-btn:hover {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  border-style: solid;
}

.edit-record-row {
  display: flex;
  gap: 4px;
  align-items: center;
  padding: 4px 0;
  border-top: 1px dotted var(--qyc-line);
  font-size: 13px;

  &:first-of-type {
    border-top: 0;
  }
}

.remove-row-btn {
  width: 24px;
  height: 24px;
  flex: 0 0 24px;
  border: 1px solid transparent;
  border-radius: 6px;
  background: transparent;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  font-weight: 800;
  cursor: pointer;
  padding: 0;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.remove-row-btn:hover {
  border-color: var(--qyc-danger);
  color: var(--qyc-danger);
}

.form-input {
  height: 28px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  padding: 0 8px;
  outline: none;
  flex: 1;
  transition: border-color 0.15s ease;
}

.form-input:focus {
  border-color: var(--qyc-vermilion);
}

.form-input--key {
  flex: 1;
  min-width: 60px;
}

.form-input--note {
  flex: 0.7;
  min-width: 50px;
}

.form-select {
  height: 28px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  padding: 0 6px;
  outline: none;
  cursor: pointer;
}

.form-select:focus {
  border-color: var(--qyc-vermilion);
}

.form-select--sm {
  min-width: 72px;
  flex: 0 0 auto;
}
