
.event-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 42%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.sub-header,
.event-title-row,
.crisis-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  font-size: 15px;
}

.event-section,
.event-card,
.crisis-card {
  position: relative;
  z-index: 1;
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.event-section {
  padding: 10px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.timeline {
  display: grid;
  gap: 8px;
  margin: 10px 0 0;
  padding: 0;
  list-style: none;
}

.timeline-item {
  display: grid;
  grid-template-columns: 18px minmax(0, 1fr);
  gap: 8px;
}

.timeline-rail {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.time-diamond {
  color: var(--qyc-vermilion);
  font-size: 12px;
  line-height: 1;
}

.rail-line {
  flex: 1;
  width: 1px;
  margin-top: 2px;
  background: var(--qyc-vermilion-faded);
  opacity: 0.5;
}

.event-card,
.crisis-card {
  padding: 10px;
}

.case-no {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0.08em;
}

time {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
}

.event-card strong,
.crisis-card strong {
  display: block;
  margin-top: 5px;
  color: var(--qyc-ink);
  font-size: 14px;
}

.impact-field,
.severity-field,
.trigger-field {
  display: block;
  margin-top: 8px;
}

.impact-field span,
.severity-field span,
.trigger-field span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.impact-pill {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 700;
}

.impact-pill.positive {
  background: rgba(74, 124, 63, 0.16);
  color: var(--qyc-ok);
}

.impact-pill.negative {
  background: rgba(178, 34, 34, 0.16);
  color: var(--qyc-danger);
}

.impact-pill.pending {
  background: rgba(122, 101, 80, 0.16);
  color: var(--qyc-ink-faint);
}

.impact-pill.neutral {
  background: rgba(61, 90, 128, 0.16);
  color: var(--qyc-info);
}

.trigger-field p {
  padding: 6px 8px;
  border: 1px dashed var(--qyc-warn);
  border-radius: 8px;
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.5;
  background: rgba(184, 115, 22, 0.05);
}

.crisis-list {
  display: grid;
  gap: 10px;
  margin-top: 8px;
}

.crisis-card {
  overflow: hidden;
  border-left-width: 5px;
}

.crisis-card.low {
  border-left-color: var(--qyc-info);
}

.crisis-card.medium {
  border-left-color: var(--qyc-warn);
}

.crisis-card.high,
.crisis-card.critical {
  border-left-color: var(--qyc-danger);
}

.crisis-alarm {
  display: flex;
  align-items: center;
  gap: 6px;
  margin: -10px -10px 8px;
  padding: 4px 10px;
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0.06em;
}

.crisis-alarm.low {
  background: rgba(61, 90, 128, 0.12);
  color: var(--qyc-info);
}

.crisis-alarm.medium {
  background: rgba(184, 115, 22, 0.14);
  color: var(--qyc-warn);
}

.crisis-alarm.high {
  background: rgba(178, 34, 34, 0.14);
  color: var(--qyc-danger);
}

.crisis-alarm.critical {
  background: rgba(178, 34, 34, 0.22);
  color: var(--qyc-danger);
  animation: alarm-blink 1.4s ease-in-out infinite;
}

@keyframes alarm-blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.55;
  }
}

.alarm-dot {
  font-size: 10px;
}

.severity-field b {
  color: var(--qyc-vermilion);
  font-size: 13px;
}

.edit-btn,
.small-btn,
.danger-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.time-input {
  max-width: 150px;
}

.empty-hint {
  padding: 10px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}
