
.intel-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 42%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.sub-header,
.node-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
h5,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  font-size: 15px;
}

h5 {
  color: var(--qyc-vermilion);
  font-size: 15px;
}

.intel-summary {
  display: grid;
  grid-template-columns: minmax(0, 0.8fr) minmax(0, 1.2fr);
  gap: 8px;
}

.summary-card,
.network-card,
.node-card {
  position: relative;
  z-index: 1;
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.summary-card,
.network-card {
  padding: 10px;
}

.summary-card.full {
  grid-column: 1 / -1;
}

.summary-card span,
.field-grid span,
.long-field span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.gauge {
  display: grid;
  gap: 6px;
}

.gauge-track {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 3px;
}

.gauge-seg {
  height: 8px;
  border-radius: 2px;
  background: var(--qyc-paper-dark);
}

.gauge-seg.on {
  box-shadow: 0 0 4px currentColor;
}

.summary-card strong {
  font-size: 18px;
}

.summary-card p,
.long-field p {
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.5;
}

.network-list {
  display: grid;
  gap: 10px;
  margin-top: 8px;
}

.node-card {
  padding: 10px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.signal {
  display: inline-flex;
  align-items: flex-end;
  gap: 2px;
  height: 16px;
}

.signal-bar {
  width: 3px;
  background: var(--qyc-paper-dark);
  border-radius: 1px;
}

.signal-bar:nth-child(1) {
  height: 4px;
}

.signal-bar:nth-child(2) {
  height: 7px;
}

.signal-bar:nth-child(3) {
  height: 10px;
}

.signal-bar:nth-child(4) {
  height: 13px;
}

.signal-bar.on {
  background: var(--qyc-vermilion);
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin-top: 8px;
}

.long-field {
  display: block;
  margin-top: 8px;
}

.seal-line {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 10px;
  letter-spacing: 0.1em;
  text-align: center;
  opacity: 0.7;
  margin-bottom: 4px;
}

.telegram {
  font-family: var(--qyc-font-mono);
  letter-spacing: 0.04em;
}

.reliability {
  font-size: 12px;
  font-weight: 800;
}

.edit-btn,
.small-btn,
.danger-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.title-input {
  font-weight: 800;
}

.empty-hint {
  padding: 10px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}

@media (max-width: 360px) {
  .intel-summary,
  .field-grid {
    grid-template-columns: 1fr;
  }
}
