
.world-section {
  padding: 12px;
}

.title-row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 10px;
}

.eyebrow {
  color: var(--qyc-vermilion-faded);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
  letter-spacing: 0.12em;
}

h1 {
  margin: 2px 0 0;
  font-size: 18px;
  line-height: 1.2;
  font-family: var(--qyc-font-title);
  letter-spacing: 0.06em;
}

.live-badge {
  border: 2px solid var(--qyc-ok);
  border-radius: 999px;
  color: var(--qyc-ok);
  font-family: var(--qyc-font-mono);
  font-size: 13px;
  padding: 3px 10px;
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(128px, 1fr));
  gap: 6px;
  color: var(--qyc-ink);
  font-size: 14px;
}

.event-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-top: 10px;
  border-top: 1px dashed var(--qyc-line-strong);
  padding-top: 10px;
}

.event-label,
.meeting-badge {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  color: var(--qyc-ink-dim);
  font-size: 14px;
  padding: 4px 10px;
}

.meeting-badge.active {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.event-text {
  flex: 1 1 220px;
  color: var(--qyc-ink);
  font-size: 15px;
}

.meeting-row {
  margin-top: 8px;
}

.meeting-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  color: var(--qyc-ink-dim);
  font-size: 14px;
  padding: 4px 10px;
}

.meeting-badge.active {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

/* ── 编辑模式 ── */
.title-actions {
  display: flex;
  gap: 6px;
  align-items: center;
}

.edit-toggle {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 700;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.edit-toggle:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.edit-toggle.active {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.edit-field {
  display: flex;
  flex-direction: column;
  gap: 3px;
  font-size: 13px;
}

.edit-field--wide {
  flex: 1;
}

.edit-label {
  color: var(--qyc-ink-faint);
  font-size: 11px;
  letter-spacing: 0.06em;
}

.edit-static {
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 30px;
}

.edit-combo {
  display: flex;
  gap: 4px;
}

.edit-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: flex-end;
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px dashed var(--qyc-line-strong);
}

.form-input {
  height: 30px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 13px;
  padding: 0 8px;
  outline: none;
  transition: border-color 0.15s ease;
}

.form-input:focus {
  border-color: var(--qyc-vermilion);
}

.form-select {
  height: 30px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 13px;
  padding: 0 6px;
  outline: none;
  cursor: pointer;
  min-width: 100px;
}

.form-select:focus {
  border-color: var(--qyc-vermilion);
}
