
.modal-mask {
  position: fixed;
  z-index: 9999;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 14px;
  background: rgba(26, 14, 8, 0.42);
  backdrop-filter: blur(2px);
}

.node-modal {
  width: min(520px, 100%);
  max-height: 88vh;
  overflow: auto;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 14px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  box-shadow: 0 18px 50px rgba(26, 14, 8, 0.28);
  padding: 14px;
}

.modal-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 10px;
  border-bottom: 1px solid var(--qyc-vermilion-faded);
  padding-bottom: 10px;
  margin-bottom: 10px;
}

.modal-kicker {
  margin: 0 0 4px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

.modal-header h2 {
  margin: 0;
  font-family: var(--qyc-font-title);
  font-size: 20px;
}

.close-btn {
  width: 30px;
  height: 30px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  cursor: pointer;
}

.status-row {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 10px;
}

.status-chip,
.branch-chip,
.days-chip {
  border: 1px solid var(--qyc-line);
  border-radius: 999px;
  background: var(--qyc-paper);
  font-size: 12px;
  font-weight: 700;
  padding: 3px 9px;
}

.status-已完成 {
  color: var(--qyc-ok);
  border-color: var(--qyc-ok);
}
.status-主要 {
  color: var(--qyc-warn);
  border-color: var(--qyc-warn);
}
.status-次要 {
  color: var(--qyc-info);
  border-color: var(--qyc-info);
}
.status-可启动 {
  color: var(--qyc-ok);
  border-color: var(--qyc-line-strong);
}
.status-锁定 {
  color: var(--qyc-ink-faint);
}

.detail-section {
  border: 1px solid var(--qyc-line);
  border-radius: 10px;
  background: rgba(242, 232, 213, 0.62);
  padding: 10px;
  margin-top: 8px;
}

.detail-section h3 {
  margin: 0 0 8px;
  color: var(--qyc-vermilion);
  font-size: 14px;
}

.plain-text,
.note-text {
  margin: 0;
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.55;
}

.note-text {
  margin-top: 6px;
  color: var(--qyc-ink-faint);
}
.empty-hint {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.pre-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 5px;
}

.pre-list li {
  display: flex;
  gap: 6px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
}

.pre-list li.done {
  color: var(--qyc-ok);
  font-weight: 700;
}

.progress-meta {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  margin-bottom: 6px;
}

.progress-bar {
  height: 9px;
  overflow: hidden;
  border: 1px solid var(--qyc-line);
  border-radius: 999px;
  background: var(--qyc-paper-dark);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
}

.progress-fill.major {
  background: var(--qyc-warn);
}
.progress-fill.minor {
  background: var(--qyc-info);
}

.start-date {
  margin-top: 6px;
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.complete-box {
  border: 1px solid var(--qyc-ok);
  border-radius: 8px;
  color: var(--qyc-ok);
  font-size: 13px;
  font-weight: 800;
  padding: 8px;
}

.ability-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.ability-tag {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink-dim);
  font-size: 12px;
  padding: 4px 8px;
}
