
.admin-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 42%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.level-header,
.card-title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-header,
.level-group,
.division-card {
  position: relative;
  z-index: 1;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
h5,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  color: var(--qyc-ink);
  font-size: 15px;
}

h5 {
  color: var(--qyc-vermilion);
  font-size: 15px;
}

.level-group {
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
  padding: 12px;
}

.level-header {
  margin-bottom: 4px;
}

.level-seal {
  display: grid;
  width: 32px;
  height: 32px;
  flex: 0 0 32px;
  place-items: center;
  border: 2px solid var(--qyc-vermilion);
  border-radius: 8px;
  background: var(--qyc-paper);
  font-size: 16px;
}

.level-seal.low {
  border-color: var(--qyc-ok);
}

.level-seal.mid {
  border-color: var(--qyc-warn);
}

.level-seal.high {
  border-color: var(--qyc-accent);
}

.level-count {
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.division-list {
  display: grid;
  gap: 10px;
}

.division-card {
  border: 1px solid var(--qyc-line);
  border-radius: 10px;
  background: var(--qyc-paper);
  padding: 10px;
}

.division-card.relation-defiant {
  border-left: 3px solid var(--qyc-warn);
}

.division-card.relation-hostile {
  border-left: 3px solid var(--qyc-danger);
  background: rgba(178, 34, 34, 0.04);
}

.division-emblem {
  color: var(--qyc-vermilion);
  font-size: 16px;
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin-top: 8px;
}

.field-grid span,
.long-field span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.long-field {
  display: block;
  margin-top: 8px;
}

.long-field p {
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.5;
}

.edit-btn,
.small-btn,
.danger-btn,
.add-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover,
.add-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.add-btn {
  justify-self: center;
  padding: 8px 16px;
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.title-input {
  flex: 1;
  min-width: 0;
  font-weight: 800;
}

.empty-hint {
  padding: 16px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
  border: 1px dashed var(--qyc-line);
  border-radius: 10px;
}

@media (max-width: 360px) {
  .field-grid {
    grid-template-columns: 1fr;
  }
}
