
.status-panel {
  width: 100%;
  padding: 6px 6px 0;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
}

.dossier-shell {
  overflow: hidden;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 16px 16px 0 0;
  background:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(139, 119, 90, 0.04) 2px,
      rgba(139, 119, 90, 0.04) 4px
    ),
    radial-gradient(
      ellipse 90% 70% at 50% 30%,
      var(--qyc-paper-light) 0%,
      var(--qyc-paper) 55%,
      var(--qyc-paper-dark) 100%
    );
  box-shadow:
    0 4px 24px rgba(44, 24, 16, 0.14),
    inset 0 0 60px rgba(139, 119, 90, 0.08);
}

.dossier-body {
  padding: 14px 12px 86px;
}

.section-header {
  display: flex;
  gap: 10px;
  align-items: flex-start;
  margin-bottom: 12px;
}

.seal {
  display: grid;
  width: 46px;
  height: 46px;
  flex: 0 0 46px;
  place-items: center;
  border: 2px solid var(--qyc-vermilion);
  border-radius: 10px;
  background: var(--qyc-paper-light);
  box-shadow:
    inset 0 0 0 2px var(--qyc-paper-light),
    0 0 0 1px var(--qyc-vermilion-faded);
  color: var(--qyc-vermilion);
  font-size: 23px;
}

.section-kicker {
  margin: 2px 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
  letter-spacing: 0.12em;
}

.section-header h2 {
  margin: 0;
  font-size: 21px;
  letter-spacing: 0.04em;
}

.summary-card,
.paper-card {
  border: 1px solid var(--qyc-line);
  border-radius: 10px;
  background: var(--qyc-paper-light);
  padding: 12px;
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.summary-card {
  margin-bottom: 10px;
}

.summary-label {
  display: inline-flex;
  margin-bottom: 6px;
  border: 1px solid var(--qyc-vermilion);
  border-radius: 999px;
  color: var(--qyc-vermilion);
  font-size: 13px;
  padding: 3px 10px;
}

.summary-card p,
.paper-text {
  margin: 0;
  color: var(--qyc-ink-dim);
  font-size: 15px;
  line-height: 1.55;
}

.paper-card {
  position: relative;
  min-height: 148px;
}

.paper-line {
  height: 1px;
  margin-bottom: 12px;
  background: linear-gradient(90deg, transparent, var(--qyc-vermilion), transparent);
}

.paper-title {
  margin: 0 0 8px;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-weight: 800;
  font-size: 18px;
}
