
.org-tree {
  padding: 4px 2px;
}

.org-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
}

.org-title {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.04em;
}

.edit-btn {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 700;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.edit-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.edit-btn.active {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.triad-row {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 10px;
  padding: 8px;
  border: 1px dashed var(--qyc-vermilion-faded);
  border-radius: 8px;
  background: rgba(184, 56, 30, 0.04);
}

.triad-chip {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 600;
  padding: 3px 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.triad-chip:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.triad-decision {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.triad-exec {
  border-color: var(--qyc-info);
  color: var(--qyc-info);
}

.triad-supervise {
  border-color: var(--qyc-accent);
  color: var(--qyc-accent);
}

.empty-hint {
  padding: 18px 8px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}

.add-top-btn {
  width: 100%;
  margin-top: 10px;
  height: 32px;
  border: 1px dashed var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.add-top-btn:hover {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  border-style: solid;
}

.tree-root {
  list-style: none;
  margin: 0;
  padding: 0;
}
