
.char-grid-panel {
  padding: 4px 2px;
}

.grid-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
}

.grid-kicker {
  margin: 0;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

.grid-header h3 {
  margin: 2px 0 0;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-size: 16px;
  font-weight: 800;
}

.edit-btn {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 700;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.edit-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.edit-btn.active {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.sub-tabs {
  display: flex;
  gap: 6px;
  margin-bottom: 8px;
  border-bottom: 1px solid var(--qyc-line);
}

.sub-tab {
  position: relative;
  padding: 6px 12px;
  border: none;
  background: transparent;
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-ui);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: color 0.15s ease;
}

.sub-tab.active {
  color: var(--qyc-vermilion);
}

.sub-tab.active::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -1px;
  height: 2px;
  background: var(--qyc-vermilion);
}

.count {
  margin-left: 4px;
  color: var(--qyc-ink-faint);
  font-size: 11px;
}

.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-bottom: 10px;
  padding: 8px;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper-light);
}

.search-input {
  flex: 1 1 160px;
  min-width: 120px;
}

.filter-item {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
}

.filter-label {
  color: var(--qyc-ink-faint);
  white-space: nowrap;
}

.form-input,
.form-select {
  height: 28px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  padding: 0 8px;
  outline: none;
  transition: border-color 0.15s ease;
}

.form-input:focus,
.form-select:focus {
  border-color: var(--qyc-vermilion);
}

.form-select {
  padding: 0 6px;
  cursor: pointer;
}

.empty-hint {
  padding: 24px;
  text-align: center;
  color: var(--qyc-ink-faint);
  font-size: 13px;
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
  gap: 8px;
}

.pager {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  margin-top: 12px;
  padding: 8px 0;
  border-top: 1px dashed var(--qyc-line);
}

.pager-btn {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink-dim);
  font-size: 12px;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.pager-btn:hover:not(:disabled) {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.pager-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.pager-info {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.edit-zone {
  margin-top: 12px;
  padding: 10px;
  border: 1px dashed var(--qyc-vermilion-faded);
  border-radius: 8px;
  background: rgba(184, 56, 30, 0.04);
}

.add-btn {
  height: 30px;
  border: 1px solid var(--qyc-vermilion);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  color: var(--qyc-vermilion);
  font-size: 13px;
  font-weight: 700;
  padding: 0 14px;
  cursor: pointer;
  transition: background 0.15s ease;
}

.add-btn:hover {
  background: rgba(184, 56, 30, 0.08);
}

.edit-hint {
  margin: 8px 0 0;
  color: var(--qyc-ink-faint);
  font-size: 11px;
}
