
.modal-mask {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: grid;
  place-items: center;
  padding: 12px;
  background: rgba(0, 0, 0, 0.54);
  backdrop-filter: blur(4px);
}

.char-modal {
  width: min(480px, 92vw);
  max-height: 82vh;
  overflow-y: auto;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 12px;
  background:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(139, 119, 90, 0.04) 2px,
      rgba(139, 119, 90, 0.04) 4px
    ),
    var(--qyc-paper-light);
  color: var(--qyc-ink);
  box-shadow: 0 18px 55px rgba(44, 24, 16, 0.45);
}

.modal-header {
  position: sticky;
  top: 0;
  z-index: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 14px 10px;
  border-bottom: 1px solid var(--qyc-vermilion-faded);
  background: var(--qyc-paper-light);
}

.modal-title {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 16px;
  font-weight: 800;
  letter-spacing: 0.04em;
}

.header-actions {
  display: flex;
  gap: 6px;
  align-items: center;
}

.edit-btn {
  height: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  font-weight: 700;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.edit-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.edit-btn.active {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.detail-value {
  color: var(--qyc-ink);
  font-size: 13px;
  line-height: 1.5;
  word-break: break-all;
}

.close-btn {
  height: 28px;
  width: 28px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 14px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.close-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.empty-hint {
  padding: 24px;
  text-align: center;
  color: var(--qyc-ink-faint);
  font-size: 13px;
}

.detail-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px 12px;
  padding: 12px 14px;
}

.detail-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.detail-item--full {
  grid-column: 1 / -1;
}

.detail-label {
  color: var(--qyc-ink-faint);
  font-size: 12px;
  font-weight: 600;
}

.form-input,
.form-select {
  height: 28px;
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  padding: 0 8px;
  outline: none;
  transition: border-color 0.15s ease;
}

.form-input:focus,
.form-select:focus {
  border-color: var(--qyc-vermilion);
}

.form-select {
  padding: 0 6px;
  cursor: pointer;
}

.form-textarea {
  border: 1px solid var(--qyc-line);
  border-radius: 6px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 12px;
  padding: 6px 8px;
  outline: none;
  resize: vertical;
  transition: border-color 0.15s ease;
}

.form-textarea:focus {
  border-color: var(--qyc-vermilion);
}

.edit-combo {
  display: flex;
  gap: 4px;
}

.edit-combo .form-select {
  flex: 0 0 90px;
}

.edit-combo .form-input {
  flex: 1 1 auto;
}

.history-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.mini-btn {
  height: 24px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 6px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink-dim);
  font-size: 11px;
  padding: 0 8px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.mini-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.mini-btn--danger:hover {
  border-color: var(--qyc-danger);
  color: var(--qyc-danger);
}

.history-edit-row {
  display: flex;
  gap: 4px;
  margin-top: 4px;
}

.form-input--time {
  flex: 0 0 90px;
}

.form-input--event {
  flex: 1 1 auto;
}

.form-input--src {
  flex: 0 0 60px;
}

.danger-zone {
  margin-top: 8px;
  padding-top: 10px;
  border-top: 1px dashed var(--qyc-line);
}

.danger-btn {
  height: 30px;
  border: 1px solid var(--qyc-danger);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-danger);
  font-size: 12px;
  font-weight: 700;
  padding: 0 14px;
  cursor: pointer;
  transition: background 0.15s ease;
}

.danger-btn:hover {
  background: rgba(178, 34, 34, 0.08);
}

/* ── 只读履历列表 ── */
.history-view {
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
  list-style: none;
}

.history-view li {
  display: flex;
  gap: 6px;
  font-size: 12px;
  line-height: 1.5;
  color: var(--qyc-ink-dim);
}

.hv-time {
  flex-shrink: 0;
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
}

.hv-event {
  word-break: break-all;
}

.detail-value--dim {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}
