
.char-card {
  display: flex;
  flex-direction: column;
  gap: 5px;
  padding: 8px;
  border: 1px solid var(--qyc-line);
  border-left: 3px solid var(--qyc-ink-faint);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease,
    transform 0.1s ease;
}

.char-card:hover {
  border-color: var(--qyc-vermilion-faded);
  box-shadow: 0 3px 10px rgba(44, 24, 16, 0.1);
  transform: translateY(-1px);
}

.char-card.safety-ok {
  border-left-color: var(--qyc-ok);
}
.char-card.safety-minor {
  border-left-color: #b8a016;
}
.char-card.safety-warn {
  border-left-color: var(--qyc-warn);
}
.char-card.safety-danger,
.char-card.safety-dead,
.char-card.is-dead {
  border-left-color: var(--qyc-danger);
  opacity: 0.62;
  background: var(--qyc-paper);
}
.char-card.is-abnormal {
  border-left-color: var(--qyc-accent);
}

.card-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 6px;
}

.head-actions {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.card-del-btn {
  width: 18px;
  height: 18px;
  display: grid;
  place-items: center;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 4px;
  background: var(--qyc-paper);
  color: var(--qyc-ink-faint);
  font-size: 11px;
  cursor: pointer;
  padding: 0;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.card-del-btn:hover {
  border-color: var(--qyc-danger);
  color: var(--qyc-danger);
  background: rgba(178, 34, 34, 0.06);
}

.char-name {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.03em;
}

.safety-badge {
  flex-shrink: 0;
  font-size: 11px;
  font-weight: 700;
  padding: 1px 7px;
  border-radius: 999px;
  color: #fff;
  white-space: nowrap;
}

.card-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  font-size: 12px;
  line-height: 1.45;
  overflow-wrap: break-word;
  word-break: break-all;
}

.info-tag {
  color: var(--qyc-ink-faint);
}

.info-duty {
  color: var(--qyc-ink);
  font-weight: 600;
}

.info-loc {
  color: var(--qyc-ink-dim);
}

.info-activity {
  color: var(--qyc-ink-faint);
  font-size: 11px;
}

.abnormal-tag {
  align-self: flex-start;
  padding: 1px 6px;
  border: 1px solid var(--qyc-accent);
  border-radius: 999px;
  color: var(--qyc-accent);
  font-size: 11px;
  font-weight: 700;
}
