
.finance-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.summary-grid,
.section-card {
  position: relative;
  z-index: 1;
}

.panel-header,
.sub-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  color: var(--qyc-ink);
  font-size: 15px;
}

.summary-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  gap: 8px;
}

.summary-tile,
.section-card {
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.summary-tile {
  min-width: 0;
  padding: 11px;
}

.status-tile.critical {
  border-color: var(--qyc-danger);
  background: radial-gradient(ellipse at center, rgba(178, 34, 34, 0.08), transparent 70%), var(--qyc-paper-light);
}

.status-tile.warn {
  border-color: var(--qyc-warn);
}

.status-tile.ok {
  border-color: var(--qyc-ok);
}

.tile-label {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 6px;
}

.status-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.status-dot {
  width: 10px;
  height: 10px;
  flex: 0 0 10px;
  border-radius: 999px;
  box-shadow: 0 0 6px currentColor;
}

.status-tile strong {
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-size: 18px;
  font-weight: 800;
}

.balance-body {
  display: flex;
  align-items: baseline;
  gap: 6px;
}

.balance-tile strong {
  font-family: var(--qyc-font-title);
  font-size: 20px;
  font-weight: 800;
}

.balance-tile strong.positive {
  color: var(--qyc-ok);
}

.balance-tile strong.negative {
  color: var(--qyc-danger);
}

.balance-unit {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.section-card {
  padding: 11px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.currency-text {
  color: var(--qyc-ink-dim);
  font-size: 14px;
  line-height: 1.55;
}

.bar-list {
  display: grid;
  gap: 10px;
}

.bar-row {
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(0, 1.4fr) minmax(0, 0.6fr);
  align-items: center;
  gap: 8px;
}

.bar-label {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.bar-name {
  color: var(--qyc-ink);
  font-size: 13px;
  font-weight: 600;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bar-track {
  position: relative;
  height: 10px;
  border-radius: 999px;
  background: rgba(188, 171, 149, 0.25);
  overflow: hidden;
}

.bar-row.income .bar-track i {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--qyc-ok), #6a9c5f);
}

.bar-row.expense .bar-track i {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--qyc-vermilion), var(--qyc-warn));
}

.bar-value {
  text-align: right;
}

.bar-value b {
  color: var(--qyc-ink);
  font-family: var(--qyc-font-mono);
  font-size: 13px;
}

.audit-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.audit-grid span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.audit-grid b {
  color: var(--qyc-ink);
  font-size: 14px;
}

.edit-btn,
.small-btn,
.danger-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.title-input {
  flex: 1;
  min-width: 0;
  font-weight: 700;
}

.empty-hint {
  padding: 10px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}

@media (max-width: 360px) {
  .summary-grid,
  .audit-grid {
    grid-template-columns: 1fr;
  }

  .bar-row {
    grid-template-columns: 1fr;
    gap: 4px;
  }

  .bar-value {
    text-align: left;
  }
}
