
.external-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 42%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.relation-table,
.add-btn,
.empty-hint {
  position: relative;
  z-index: 1;
}

.panel-header,
.force-title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  min-width: 0;
  color: var(--qyc-vermilion);
  font-size: 15px;
}

.relation-table {
  display: grid;
  gap: 10px;
}

.force-card {
  position: relative;
  z-index: 1;
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  padding: 10px;
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.force-emblem {
  display: grid;
  width: 24px;
  height: 24px;
  flex: 0 0 24px;
  place-items: center;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.matrix-row {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin-top: 8px;
}

.matrix-row span,
.force-detail span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.matrix-row b,
.pill {
  display: inline-block;
  color: var(--qyc-ink);
  font-size: 13px;
}

.pill.solid {
  padding: 2px 8px;
  border: 1px solid;
  border-radius: 999px;
  font-weight: 800;
}

.strategy {
  color: var(--qyc-info);
}

.influence-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 9px;
}

.influence-bar {
  position: relative;
  flex: 1;
  height: 8px;
  overflow: hidden;
  border-radius: 999px;
  background: var(--qyc-paper-dark);
  background-image: repeating-linear-gradient(
    90deg,
    transparent 0,
    transparent 9px,
    rgba(122, 101, 80, 0.4) 9px,
    rgba(122, 101, 80, 0.4) 10px
  );
}

.influence-bar i {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--qyc-info), var(--qyc-vermilion));
}

.influence-tick {
  flex: 0 0 auto;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  font-weight: 800;
}

.force-detail {
  display: grid;
  gap: 8px;
  margin-top: 10px;
  border-top: 2px dashed var(--qyc-vermilion);
  padding-top: 10px;
}

.seal-line {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 10px;
  letter-spacing: 0.1em;
  text-align: center;
  opacity: 0.7;
}

.force-detail p {
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.5;
}

.force-detail .telegram {
  font-family: var(--qyc-font-mono);
  letter-spacing: 0.04em;
}

.edit-btn,
.add-btn,
.danger-btn,
.collapse-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.collapse-btn {
  width: 28px;
  padding: 5px 0;
}

.edit-btn.active,
.add-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.title-input {
  flex: 1;
  min-width: 0;
  font-weight: 800;
}

.empty-hint {
  border: 1px dashed var(--qyc-line);
  border-radius: 10px;
  padding: 12px;
  color: var(--qyc-ink-faint);
  text-align: center;
}

@media (max-width: 360px) {
  .matrix-row {
    grid-template-columns: 1fr;
  }
}
