
.tech-panel {
  padding: 4px 2px;
}

.tech-header,
.dag-toolbar,
.modal-header,
.candidate-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.tech-kicker,
.modal-kicker {
  margin: 0 0 4px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

.tech-header h3,
.modal-header h3 {
  margin: 0;
  font-family: var(--qyc-font-title);
  font-size: 18px;
}

.autonomy-badge {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  background: var(--qyc-paper-light);
  font-size: 12px;
  font-weight: 800;
  padding: 5px 10px;
}
.autonomy-badge.ok {
  color: var(--qyc-ok);
  border-color: var(--qyc-ok);
}
.autonomy-badge.warn {
  color: var(--qyc-warn);
  border-color: var(--qyc-warn);
}
.autonomy-badge.danger {
  color: var(--qyc-danger);
  border-color: var(--qyc-danger);
}

.status-strip {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin: 10px 0;
}

.status-item,
.progress-overview,
.dag-section,
.complete-panel {
  border: 1px solid var(--qyc-line);
  border-radius: 10px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.05);
}

.status-item {
  padding: 8px;
}
.status-item .label {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
}
.status-item .value {
  display: block;
  margin-top: 3px;
  font-size: 13px;
  font-weight: 800;
}

.outline-btn,
.ghost-btn,
.confirm-btn {
  height: 30px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 800;
  padding: 0 10px;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}
.outline-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}
.confirm-btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.complete-panel {
  padding: 14px;
  margin-bottom: 10px;
  text-align: center;
}
.complete-stamp {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 20px;
  font-weight: 900;
}
.complete-quote {
  color: var(--qyc-ink-dim);
  line-height: 1.55;
}
.complete-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
  text-align: left;
  font-size: 13px;
}
.complete-grid span {
  color: var(--qyc-ink-faint);
}
.archive-note {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.progress-overview,
.dag-section {
  padding: 10px;
  margin-bottom: 10px;
}
.section-title {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 15px;
  font-weight: 900;
}
.branch-grid {
  display: grid;
  gap: 8px;
  margin-top: 8px;
}
.branch-meta {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  font-size: 12px;
}
.branch-bar {
  height: 7px;
  overflow: hidden;
  border-radius: 999px;
  background: var(--qyc-paper-dark);
  margin-top: 4px;
}
.branch-fill {
  height: 100%;
  background: var(--qyc-ok);
}

.view-switch {
  display: inline-flex;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  overflow: hidden;
}
.view-switch button {
  border: 0;
  border-right: 1px solid var(--qyc-line);
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  padding: 5px 8px;
  cursor: pointer;
}
.view-switch button:last-child {
  border-right: 0;
}
.view-switch button.active {
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
  font-weight: 900;
}

.node-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
  gap: 8px;
  margin-top: 10px;
}
.node-card,
.compact-node,
.dag-node {
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  text-align: left;
  cursor: pointer;
}
.node-card {
  min-height: 72px;
  padding: 8px;
}
.node-title {
  display: block;
  font-size: 13px;
  font-weight: 900;
}
.node-meta {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-top: 5px;
}
.mini-progress {
  display: block;
  height: 5px;
  border-radius: 999px;
  background: var(--qyc-paper-dark);
  overflow: hidden;
  margin-top: 8px;
}
.mini-progress i {
  display: block;
  height: 100%;
  background: var(--qyc-warn);
}

.status-已完成 {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
}
.status-主要 {
  border-color: var(--qyc-warn);
}
.status-次要 {
  border-color: var(--qyc-info);
}
.status-可启动 {
  border-style: dashed;
}
.status-锁定 {
  color: var(--qyc-ink-faint);
  opacity: 0.72;
}

.branch-node-list {
  display: grid;
  gap: 8px;
  margin-top: 10px;
}
.branch-detail {
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  padding: 8px;
}
.branch-detail summary {
  cursor: pointer;
  font-weight: 900;
}
.branch-nodes {
  display: grid;
  gap: 5px;
  margin-top: 8px;
}
.compact-node {
  display: grid;
  grid-template-columns: auto 1fr auto;
  gap: 6px;
  align-items: center;
  padding: 5px 7px;
  font-size: 12px;
}
.compact-node small {
  color: var(--qyc-ink-faint);
}

.dag-container {
  overflow-x: auto;
  display: flex;
  gap: 10px;
  padding: 8px 2px;
  margin-top: 10px;
}
.dag-layer {
  min-width: 150px;
  display: grid;
  align-content: start;
  gap: 7px;
}
.layer-label {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  font-weight: 900;
}
.dag-node {
  position: relative;
  min-height: 44px;
  padding: 6px;
  font-size: 11px;
}
.dag-node b {
  float: right;
}
.dag-node i {
  position: absolute;
  left: 6px;
  bottom: 4px;
  height: 4px;
  border-radius: 999px;
  background: currentColor;
}

.modal-mask {
  position: fixed;
  z-index: 9998;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 14px;
  background: rgba(26, 14, 8, 0.42);
  backdrop-filter: blur(2px);
}
.candidate-modal {
  width: min(560px, 100%);
  max-height: 88vh;
  display: flex;
  flex-direction: column;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 14px;
  background: var(--qyc-paper-light);
  padding: 14px;
  box-shadow: 0 18px 50px rgba(26, 14, 8, 0.28);
}
.close-btn {
  width: 30px;
  height: 30px;
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  cursor: pointer;
}
.search-input {
  width: 100%;
  height: 34px;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  padding: 0 10px;
  margin: 10px 0;
}
.candidate-groups {
  overflow: auto;
  display: grid;
  gap: 8px;
  padding-right: 2px;
}
.candidate-group {
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  padding: 8px;
}
.candidate-group h4 {
  margin: 0 0 6px;
  color: var(--qyc-vermilion);
  font-size: 13px;
}
.candidate-row {
  display: flex;
  gap: 8px;
  align-items: flex-start;
  padding: 6px 0;
  border-top: 1px dashed rgba(160, 140, 116, 0.5);
  cursor: pointer;
}
.candidate-row:first-of-type {
  border-top: 0;
}
.candidate-main strong {
  display: block;
  font-size: 13px;
}
.candidate-main small {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  line-height: 1.4;
}
.candidate-actions {
  border-top: 1px solid var(--qyc-line);
  margin-top: 10px;
  padding-top: 10px;
  color: var(--qyc-ink-faint);
  font-size: 12px;
}
.candidate-actions > div {
  display: flex;
  gap: 8px;
}
.confirm-btn {
  background: var(--qyc-vermilion);
  color: var(--qyc-paper-light);
  border-color: var(--qyc-vermilion);
}
.modal-empty {
  padding: 20px;
  text-align: center;
}

@media (max-width: 420px) {
  .status-strip {
    grid-template-columns: 1fr;
  }
  .dag-toolbar,
  .candidate-actions {
    align-items: stretch;
    flex-direction: column;
  }
}
