
.personnel-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 42%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 56px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.section-card {
  position: relative;
  z-index: 1;
}

.panel-header,
.sub-header,
.card-title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  color: var(--qyc-ink);
  font-size: 15px;
}

.section-card {
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
  padding: 11px;
}

.record-count {
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.principle-text,
.rank-text {
  color: var(--qyc-ink-dim);
  font-size: 14px;
  line-height: 1.55;
}

.timeline {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 10px;
}

.timeline-item {
  display: grid;
  grid-template-columns: 20px minmax(0, 1fr);
  gap: 8px;
}

.timeline-rail {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.time-diamond {
  color: var(--qyc-vermilion);
  font-size: 12px;
  line-height: 1;
}

.rail-line {
  width: 2px;
  flex: 1;
  margin-top: 2px;
  background: linear-gradient(180deg, var(--qyc-vermilion-faded), transparent);
}

.appointment-card {
  border: 1px solid var(--qyc-line);
  border-radius: 10px;
  background: var(--qyc-paper);
  padding: 10px;
}

.case-no {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.08em;
}

.time-input {
  flex: 1;
  min-width: 0;
  font-family: var(--qyc-font-mono);
  font-size: 12px;
}

time {
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 8px;
  margin-top: 8px;
}

.field-grid span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.post-name {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 14px;
  font-weight: 800;
}

.field-grid b {
  color: var(--qyc-ink);
  font-size: 13px;
}

.edit-btn,
.small-btn,
.danger-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.empty-hint {
  padding: 10px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}

@media (max-width: 360px) {
  .field-grid {
    grid-template-columns: 1fr;
  }
}
