
.vehicle-bar {
  position: relative;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  justify-content: space-between;
  border-top: 1px solid var(--qyc-line);
  border-bottom: 1px solid var(--qyc-line);
  padding: 10px 12px;
  background: var(--qyc-paper-dark);
  cursor: pointer;
  transition: background 0.15s ease;
}

.vehicle-bar:hover,
.vehicle-bar:focus-visible {
  background: var(--qyc-paper-warm);
  outline: none;
}

.vehicle-main,
.vehicle-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  align-items: center;
}

.vehicle-title {
  font-weight: 800;
  font-size: 15px;
}

.vehicle-location,
.vehicle-state {
  color: var(--qyc-ink-dim);
  font-size: 14px;
}

.tag {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 999px;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-mono);
  font-size: 13px;
  padding: 4px 9px;
  background: var(--qyc-paper-light);
}

.vehicle-hint {
  color: var(--qyc-vermilion-faded);
  font-family: var(--qyc-font-mono);
  font-size: 12px;
  letter-spacing: 0.08em;
}
