
.military-panel {
  position: relative;
  display: grid;
  gap: 18px;
  overflow: hidden;
}

.watermark {
  position: absolute;
  top: 38%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-18deg);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 60px;
  font-weight: 800;
  letter-spacing: 0.2em;
  opacity: 0.04;
  pointer-events: none;
  z-index: 0;
}

.panel-header,
.summary-grid,
.section-card {
  position: relative;
  z-index: 1;
}

.panel-header,
.sub-header,
.card-title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.panel-kicker {
  margin: 0 0 3px;
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
}

h3,
h4,
h5,
p {
  margin: 0;
}

h3 {
  font-size: 17px;
}

h4 {
  color: var(--qyc-ink);
  font-size: 15px;
}

h5 {
  color: var(--qyc-vermilion);
  font-size: 15px;
}

.summary-grid {
  display: grid;
  grid-template-columns: minmax(0, 0.8fr) minmax(0, 1.2fr);
  gap: 8px;
}

.summary-tile,
.section-card,
.unit-card {
  position: relative;
  z-index: 1;
  border: 1px solid var(--qyc-line);
  border-radius: 12px;
  background: var(--qyc-paper-light);
  box-shadow: 0 2px 8px rgba(44, 24, 16, 0.06);
}

.summary-tile {
  min-width: 0;
  padding: 11px;
}

.total-seal {
  display: grid;
  gap: 6px;
  border: 2px solid var(--qyc-vermilion);
  background: radial-gradient(ellipse at center, rgba(184, 56, 30, 0.06), transparent 70%), var(--qyc-paper-light);
}

.seal-body {
  display: flex;
  align-items: baseline;
  gap: 6px;
}

.total-seal strong {
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-title);
  font-size: 22px;
  font-weight: 800;
}

.seal-unit {
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.tile-label,
.long-field span,
.field-grid span {
  display: block;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  margin-bottom: 4px;
}

.summary-tile strong {
  display: block;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-size: 18px;
}

.ammo-row {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.status-dot {
  width: 9px;
  height: 9px;
  flex: 0 0 9px;
  border-radius: 999px;
}

.ammo-input {
  flex: 1;
  min-width: 0;
}

.ammo-bar {
  height: 9px;
  overflow: hidden;
  margin-top: 8px;
  border-radius: 999px;
  background: var(--qyc-paper-dark);
}

.ammo-bar i {
  display: block;
  height: 100%;
  border-radius: inherit;
  background-image: repeating-linear-gradient(
    45deg,
    rgba(255, 255, 255, 0.18) 0,
    rgba(255, 255, 255, 0.18) 4px,
    transparent 4px,
    transparent 8px
  );
}

.ammo-bar.critical {
  animation: ammo-blink 1.2s ease-in-out infinite;
}

@keyframes ammo-blink {
  0%,
  100% {
    box-shadow: 0 0 0 0 rgba(178, 34, 34, 0);
  }
  50% {
    box-shadow: 0 0 0 3px rgba(178, 34, 34, 0.25);
  }
}

/* 弹药条关键词提示 */
.ammo-hint-trigger {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  margin-left: 4px;
  border: 1px solid var(--qyc-ink-faint);
  border-radius: 999px;
  color: var(--qyc-ink-faint);
  font-size: 10px;
  font-weight: 800;
  cursor: help;
  vertical-align: middle;
  user-select: none;
  transition:
    border-color 0.15s,
    color 0.15s,
    background 0.15s;
}

.ammo-hint-trigger:hover,
.ammo-hint-trigger:focus {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  outline: none;
}

.ammo-hint {
  margin-top: 8px;
  padding: 8px 10px;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  font-size: 12px;
  line-height: 1.6;
}

.ammo-hint p {
  margin: 0 0 4px;
  color: var(--qyc-ink-dim);
  font-size: 11px;
}

.ammo-hint table {
  width: 100%;
  border-collapse: collapse;
}

.ammo-hint td {
  padding: 2px 4px;
  color: var(--qyc-ink-faint);
  font-size: 12px;
}

.hint-val {
  text-align: right;
  font-family: var(--qyc-font-mono);
  font-size: 11px;
}

.hint-dot {
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 999px;
  margin-right: 4px;
}

.hint-dot.danger {
  background-color: var(--qyc-danger);
}

.hint-dot.warn {
  background-color: var(--qyc-warn);
}

.hint-dot.ok {
  background-color: var(--qyc-ok);
}

.hint-foot {
  margin-top: 4px !important;
  color: var(--qyc-ink-faint) !important;
  font-size: 10px !important;
  font-style: italic;
}

.section-card {
  padding: 11px;
}

.divider-ornament {
  margin: 6px 0 10px;
  color: var(--qyc-vermilion-faded);
  font-size: 10px;
  letter-spacing: 0.4em;
  text-align: center;
  opacity: 0.7;
}

.unit-list {
  display: grid;
  gap: 10px;
}

.unit-card {
  padding: 10px;
}

.unit-emblem {
  color: var(--qyc-vermilion);
  font-size: 16px;
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin-top: 8px;
}

.long-field {
  display: block;
  margin-top: 8px;
}

.long-field p,
.note {
  color: var(--qyc-ink-dim);
  font-size: 13px;
  line-height: 1.5;
}

.morale-stars {
  color: var(--qyc-vermilion);
  font-size: 13px;
  letter-spacing: 1px;
  margin-right: 4px;
}

.morale-text {
  color: var(--qyc-ink);
  font-size: 13px;
}

.equipment-table {
  width: 100%;
  margin-top: 8px;
  border-collapse: collapse;
  font-size: 13px;
}

.equipment-table th {
  padding: 6px 8px;
  border-bottom: 2px solid var(--qyc-vermilion);
  color: var(--qyc-vermilion);
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  letter-spacing: 0.08em;
  text-align: left;
}

.equipment-table td {
  padding: 8px;
  border-bottom: 1px solid var(--qyc-line);
  vertical-align: middle;
}

.equipment-table tbody tr:nth-child(odd) {
  background: rgba(188, 171, 149, 0.08);
}

.equip-name {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.equip-lamp {
  width: 8px;
  height: 8px;
  flex: 0 0 8px;
  border-radius: 999px;
  box-shadow: 0 0 4px currentColor;
}

.edit-btn,
.small-btn,
.danger-btn {
  border: 1px solid var(--qyc-line-strong);
  border-radius: 8px;
  background: transparent;
  color: var(--qyc-ink-dim);
  font-size: 12px;
  font-weight: 700;
  padding: 5px 9px;
  cursor: pointer;
}

.edit-btn.active,
.small-btn:hover {
  border-color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  color: var(--qyc-vermilion);
}

.danger-btn {
  color: var(--qyc-danger);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper);
  color: var(--qyc-ink);
  font-size: 13px;
  padding: 6px 8px;
}

.form-textarea {
  resize: vertical;
}

.title-input {
  flex: 1;
  min-width: 0;
  font-weight: 800;
}

.empty-hint {
  padding: 10px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
  text-align: center;
}

@media (max-width: 360px) {
  .summary-grid,
  .field-grid {
    grid-template-columns: 1fr;
  }

  .equipment-table {
    font-size: 12px;
  }
}
