
.tree-node {
  margin: 4px 0;
}

.tree-children {
  list-style: none;
  margin: 0;
  padding: 0 0 0 14px;
  position: relative;
}

/* 父子连接分支线：竖线 + 每个子节点的水平连接 */
.tree-children::before {
  content: '';
  position: absolute;
  top: 0;
  bottom: 12px;
  left: 6px;
  width: 1px;
  background: var(--qyc-line);
}

.tree-children .tree-node {
  position: relative;
}

.tree-children .tree-node::before {
  content: '';
  position: absolute;
  top: 14px;
  left: -8px;
  width: 8px;
  height: 1px;
  background: var(--qyc-line);
}

.node-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 6px;
  padding: 5px 6px;
  border: 1px solid var(--qyc-line);
  border-radius: 8px;
  background: var(--qyc-paper-light);
  font-size: 13px;
}

.node-row.is-top {
  border-color: var(--qyc-vermilion);
  box-shadow: 0 0 0 1px var(--qyc-vermilion-faded) inset;
}

.node-status-dot {
  width: 8px;
  height: 8px;
  flex: 0 0 8px;
  border-radius: 50%;
  background: var(--qyc-ink-dim);
}

.node-status-dot.revoked {
  opacity: 0.5;
}

.node-name {
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-weight: 800;
  font-size: 14px;
}

.node-name.is-top {
  color: var(--qyc-vermilion);
}

.node-name.revoked {
  color: var(--qyc-ink-faint);
  text-decoration: line-through;
}

.node-type {
  border: 1px solid var(--qyc-line);
  border-radius: 4px;
  padding: 1px 5px;
  color: var(--qyc-ink-faint);
  font-size: 11px;
}

.node-status {
  font-family: var(--qyc-font-mono);
  font-size: 11px;
  font-weight: 700;
}

.node-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 4px 12px;
  padding: 4px 8px;
  color: var(--qyc-ink-faint);
  font-size: 13px;
}

.node-task {
  color: var(--qyc-ink-dim);
}

/* ── 路径面包屑 ── */
.path-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 3px 4px;
  padding: 2px 8px 3px;
  color: var(--qyc-ink-faint);
  font-size: 11px;
  line-height: 1.4;
}

.path-label {
  opacity: 0.7;
}

.path-chip {
  border: none;
  background: transparent;
  color: var(--qyc-ink-faint);
  font-family: var(--qyc-font-ui);
  font-size: 11px;
  padding: 1px 4px;
  cursor: pointer;
  border-radius: 3px;
  transition:
    color 0.15s ease,
    background 0.15s ease;
}

.path-chip:hover {
  color: var(--qyc-vermilion);
  background: rgba(184, 56, 30, 0.08);
  text-decoration: underline;
}

.path-sep {
  color: var(--qyc-line-strong);
  font-size: 10px;
}

.path-current {
  color: var(--qyc-ink-dim);
  font-weight: 700;
}

/* ── 权势指数可视化条 ── */
.power-cell {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.power-bar {
  display: inline-block;
  width: 48px;
  height: 6px;
  border: 1px solid var(--qyc-line);
  border-radius: 3px;
  background: var(--qyc-paper-dark);
  overflow: hidden;
  vertical-align: middle;
}

.power-fill {
  display: block;
  height: 100%;
  border-radius: 2px;
  transition: width 0.3s ease;
}

/* ── 编辑模式表单控件 ── */
.form-select--sm {
  height: 22px;
  border: 1px solid var(--qyc-line);
  border-radius: 5px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 11px;
  padding: 0 4px;
  outline: none;
  cursor: pointer;
  min-width: 72px;
}

.form-select--sm:focus {
  border-color: var(--qyc-vermilion);
}

.form-input--xs {
  height: 22px;
  border: 1px solid var(--qyc-line);
  border-radius: 5px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 11px;
  padding: 0 6px;
  outline: none;
  min-width: 40px;
  max-width: 100px;
  transition: border-color 0.15s ease;
}

.form-input--xs:focus {
  border-color: var(--qyc-vermilion);
}

.form-input--num {
  width: 56px;
  height: 22px;
  border: 1px solid var(--qyc-line);
  border-radius: 5px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 11px;
  padding: 0 6px;
  outline: none;
  transition: border-color 0.15s ease;
}

.form-input--num:focus {
  border-color: var(--qyc-vermilion);
}

.edit-combo--inline {
  display: inline-flex;
  gap: 3px;
  align-items: center;
}

.edit-field--inline {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.edit-field--wide {
  display: flex;
  flex-direction: column;
  gap: 2px;
  width: 100%;
}

.edit-label {
  color: var(--qyc-ink-faint);
  font-size: 13px;
  white-space: nowrap;
}

.edit-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 3px;
  align-items: center;
  padding: 2px 0;
}

.edit-chip {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  border: 1px solid var(--qyc-line);
  border-radius: 4px;
  background: var(--qyc-paper);
  color: var(--qyc-ink-dim);
  font-size: 11px;
  padding: 1px 5px;
}

.chip-remove {
  width: 14px;
  height: 14px;
  border: none;
  border-radius: 3px;
  background: transparent;
  color: var(--qyc-ink-faint);
  font-size: 9px;
  font-weight: 800;
  cursor: pointer;
  padding: 0;
  display: grid;
  place-items: center;
  transition:
    color 0.15s ease,
    background 0.15s ease;
}

.chip-remove:hover {
  color: var(--qyc-danger);
  background: rgba(178, 34, 34, 0.08);
}

.chip-input {
  height: 20px;
  border: none;
  border-bottom: 1px dotted var(--qyc-line);
  background: transparent;
  color: var(--qyc-ink);
  font-family: var(--qyc-font-ui);
  font-size: 11px;
  padding: 0 4px;
  outline: none;
  min-width: 50px;
  flex: 0 1 auto;
}

.chip-input:focus {
  border-bottom-color: var(--qyc-vermilion);
}

.chip-add-btn {
  width: 20px;
  height: 20px;
  flex: 0 0 20px;
  border: 1px solid var(--qyc-line);
  border-radius: 5px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink-dim);
  font-size: 13px;
  font-weight: 700;
  padding: 0;
  display: grid;
  place-items: center;
  cursor: pointer;
  transition:
    border-color 0.15s ease,
    color 0.15s ease,
    background 0.15s ease;
}

.chip-add-btn:hover:not(:disabled) {
  border-color: var(--qyc-ok);
  color: var(--qyc-ok);
  background: rgba(74, 124, 63, 0.06);
}

.chip-add-btn:disabled {
  opacity: 0.4;
  cursor: default;
}

.node-array-chip {
  color: var(--qyc-ink-dim);
  font-style: italic;
  font-size: 13px;
}

.icon-btn {
  width: 22px;
  height: 22px;
  flex: 0 0 22px;
  border: 1px solid transparent;
  border-radius: 5px;
  background: transparent;
  color: var(--qyc-ink-faint);
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  padding: 0;
  display: grid;
  place-items: center;
  transition:
    border-color 0.15s ease,
    color 0.15s ease;
}

.icon-btn:hover {
  border-color: var(--qyc-vermilion);
  color: var(--qyc-vermilion);
}

.icon-btn--danger:hover {
  border-color: var(--qyc-danger);
  color: var(--qyc-danger);
}

.collapse-btn {
  margin-left: auto;
}

.rename-input {
  height: 24px;
  border: 1px solid var(--qyc-vermilion);
  border-radius: 5px;
  background: var(--qyc-paper-light);
  color: var(--qyc-ink);
  font-family: var(--qyc-font-title);
  font-size: 13px;
  font-weight: 800;
  padding: 0 6px;
  outline: none;
  min-width: 80px;
}

.tree-node.flash {
  animation: node-flash 1.2s ease;
}

@keyframes node-flash {
  0%,
  100% {
    background: transparent;
  }
  30% {
    background: rgba(184, 56, 30, 0.18);
  }
}
